import{La as n,Ma as e,Na as r,Ua as t,xa as a}from"./chunk-EI4QQVGX.js";var s=class i{static \u0275fac=function(o){return new(o||i)};static \u0275cmp=a({type:i,selectors:[["app-ministries"]],decls:82,vars:0,consts:[[1,"page-hero","ministries-hero"],[1,"page-hero-content"],[1,"scroll-indicator"],[1,"chevron"],[1,"content-section"],[1,"container"],[1,"ministry-contact"]],template:function(o,d){o&1&&(n(0,"section",0)(1,"div",1)(2,"h1"),t(3,"MINISTRIES"),e()(),n(4,"div",2),r(5,"span",3),e()(),n(6,"section",4)(7,"div",5)(8,"p"),t(9,"We have a variety of ministries meeting throughout the week. Everyone is welcome to join us."),e(),n(10,"h2"),t(11,"Adult Bible Class"),e(),n(12,"p"),t(13,"Adult Sunday class, held every Sunday morning after church service, is a study group that addresses subjects in detail that are not fully addressed in other meetings of the church. The aim of the class is to strengthen the believers in their understanding of the doctrines God gives us. We have dealt with the whole Heidelberg catechism, teaching church leadership and structure such as elders and deacons, and various other polemical subjects such as creation and proving the reality of our faith. The group allows for discussion and questions."),e(),n(14,"h2"),t(15,"Pilgrim's Progress Study Group"),e(),n(16,"p"),t(17,"This group meets roughly every two weeks on a Saturday morning. It started as an addiction training class and developed into a study on living out the Christian life practically. We are studying a modern rendition of Pilgrim's Progress. We all read a chapter before coming together to answer questions, raise difficulties that we encountered and talk about how to apply what we studied. It's a lively enthusiastic group and enjoyed by all. The fact that we come from various cultural backgrounds makes for great conversation. The main object is once again that we strengthen one another as we walk with the Lord Jesus. Hebrews 10:23-25."),e(),n(18,"h2"),t(19,"Bible Study"),e(),n(20,"p"),t(21,"This group meets every Thursday evening at 7 to study a passage from a book of the bible. We consider the meaning of each verse and seek to learn and apply what the Lord wants of us. We believe that the bible is God's infallible word given to guide us and make us holy. (John 17:17). The group is encouraged to ask questions and at times make contributions. We can't stop the preacher in church to ask a question about a matter we don't understand but this may be done here. We take time to pray as well and enjoy fellowship over a cup of tea or coffee."),e(),n(22,"h2"),t(23,"Young Adults"),e(),n(24,"p"),t(25,"The Hope Covenant young adults ministry meets every second Saturday evening, hosted on a rotating basis at the home of one of our group members. The programme usually includes some form of games or social event, a meal, a time of prayer, singing, and an hour spent discussing God's word together. The core focus is growth in God's word and the person of Jesus Christ, as well as mutual spiritual encouragement and 'building up' of one another."),e(),n(26,"p"),t(27,"We meet alongside the young adults of several sister churches, and all are warmly welcomed to join us. Lifts are available on request to those that may need them."),e(),n(28,"p",6)(29,"strong"),t(30,"Contact:"),e(),t(31," Robert Clarke (079 685 3939)"),e(),n(32,"h2"),t(33,"Ladies' Bible Study"),e(),n(34,"p"),t(35,"Our meetings take place at 10:00am on a Wednesday morning at the home of Eve Evans. We begin with tea and fellowship, followed by a time of prayer."),e(),n(36,"p"),t(37,"Our studies, which are filled with lively discussion, are largely on books of the Bible, although we also do topical studies."),e(),n(38,"p"),t(39,"Ladies of all ages are very welcome to attend."),e(),n(40,"p",6)(41,"strong"),t(42,"Contact:"),e(),t(43," Elaine Dennil"),e(),n(44,"h2"),t(45,"Titus 2 Ladies' Bible Study"),e(),n(46,"p"),t(47,'This monthly Saturday morning ministry meets at the church. Our main goal is to study the Bible, particularly focusing on "Biblical Literacy", and then apply these insights to our lives as women. This year, we are studying the book of James.'),e(),n(48,"p"),t(49,"We also use this time to identify opportunities to serve and support those in our church community who are in need. Additionally, it's a chance for us to fellowship."),e(),n(50,"h2"),t(51,"Youth Ministries"),e(),n(52,"p"),t(53,"Youth ministry is a vital part of life at Hope Covenant Church. While we believe that families should worship together and that parents have the primary responsibility of teaching God's word to their children (Deuteronomy 6:7), we do cater for children in a number of ways."),e(),n(54,"h3"),t(55,"Sunday School"),e(),n(56,"p"),t(57,"Our Sunday School classes, which are held separately from our morning service, are divided by age. The primary school children sing together for the first part, and then they split into three separate age groups for their lessons. These are based on materials that guide the students through the redemption story in the Bible from Genesis to Revelation in a three-year cycle. The high school class takes the format of a Bible study and discussion."),e(),n(58,"p",6)(59,"strong"),t(60,"Contact:"),e(),t(61," Felicity Britz (055 656 565)"),e(),n(62,"h3"),t(63,"Youth"),e(),n(64,"p"),t(65,"We have two Friday youth groups: one for Grades 1\u20137 and the other for Grades 8\u201312. Both groups enjoy a time of games and activities, followed by a Bible lesson."),e(),n(66,"p",6)(67,"strong"),t(68,"Contact:"),e(),t(69," Felicity Britz (055 656 565)"),e(),n(70,"h3"),t(71,"Defence Ministry"),e(),n(72,"p"),t(73,"Once a month we run our Defence program, which focuses on mentoring the many young men and boys in our congregation, especially those who do not have godly father figures in their homes. The men work alongside the boys on maintenance projects for the church building and teach them practical skills. This is followed by a meal and devotional and ends with a ball game."),e(),n(74,"h3"),t(75,"Holiday Bible Club"),e(),n(76,"p"),t(77,"Once a year, we organise a Holiday Bible Club for the primary school-aged children in our community. Many of the adults and teens at Hope Covenant are involved in running this program for about 100 children. They rotate through a range of activities, including singing, drama, science demonstrations, outdoor games, memory verses, snacks, and Bible lessons."),e(),n(78,"p",6)(79,"strong"),t(80,"Contact:"),e(),t(81," Felicity Britz (055 656 565)"),e()()())},styles:[".ministries-hero[_ngcontent-%COMP%]{position:relative;background:linear-gradient(#16213ebf,#0f3460cc),url(/images/ministries-card.webp) center/cover no-repeat;min-height:85vh;display:flex;align-items:center;justify-content:center;text-align:center}.page-hero-content[_ngcontent-%COMP%]   h1[_ngcontent-%COMP%]{color:#fff;font-size:3rem;letter-spacing:2px;font-weight:700}.content-section[_ngcontent-%COMP%]{padding:4rem 1.5rem}.container[_ngcontent-%COMP%]{max-width:780px;margin:0 auto}.container[_ngcontent-%COMP%] > p[_ngcontent-%COMP%]:first-of-type{text-align:center;font-size:1.05rem;color:#4a5568;margin-bottom:3rem}.content-section[_ngcontent-%COMP%]   h2[_ngcontent-%COMP%]{font-size:1.65rem;color:#1a1a2e;margin-top:3rem;margin-bottom:1rem;letter-spacing:.5px;font-weight:600}.content-section[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%]{font-size:1.2rem;color:#0078a7;margin-top:2rem;margin-bottom:.75rem;font-weight:600}.content-section[_ngcontent-%COMP%]   p[_ngcontent-%COMP%]{margin-bottom:1.15rem;font-size:.95rem;line-height:1.8;color:#4a5568}.ministry-contact[_ngcontent-%COMP%]{font-size:.9rem;color:#718096;margin-top:-.5rem;margin-bottom:1.5rem}.ministry-contact[_ngcontent-%COMP%]   strong[_ngcontent-%COMP%]{color:#4a5568}@media(max-width:768px){.ministries-hero[_ngcontent-%COMP%]{min-height:55vh}.page-hero-content[_ngcontent-%COMP%]   h1[_ngcontent-%COMP%]{font-size:2rem}}"]})};export{s as MinistriesPage};
